    js: '<script>\n(function () {\n  const root = document.getElementById("mmd-pcb");\n  if (!root) return;\n\n  const CHAT_URL = "https://chat.mmdbkk.com/start";\n\n  function withSource(url, source) {\n    try {\n      const parsed = new URL(url, window.location.origin);\n      if (!parsed.searchParams.get("source")) parsed.searchParams.set("source", source);\n      return parsed.toString();\n    } catch (error) {\n      return url;\n    }\n  }\n\n  root.querySelectorAll("[data-mmd-pcb-chat]").forEach(function (link) {\n    link.setAttribute("href", withSource(CHAT_URL, "landing_private_companion"));\n  });\n\n  root.querySelectorAll("[data-mmd-pcb-cta]").forEach(function (link) {\n    link.addEventListener("click", function () {\n      root.setAttribute("data-last-cta", link.getAttribute("data-mmd-pcb-cta") || "unknown");\n    });\n  });\n})();\n<\/script>\n'
